"""Read access to the recorded money lines (nightly artifacts in exports/).

Per docs/accounting.md the recorded lines are authoritative for statements,
notifications, and audit — consumers read them from here rather than
recomputing from order data. This module is read-only: it never writes to
exports/ or touches the order store.
"""
from __future__ import annotations

import csv
from dataclasses import dataclass
from pathlib import Path

from libs.money import Money

EXPORTS_DIR = Path(__file__).resolve().parent.parent.parent / "exports"


@dataclass(frozen=True)
class RecordedCharge:
    order_id: str
    charged_at: str  # ISO date, e.g. "2026-04-17"
    status: str  # "fulfilled" | "cancelled"
    amount: Money

    @property
    def month(self) -> str:
        return self.charged_at[:7]


@dataclass(frozen=True)
class RecordedRefundLine:
    order_id: str
    sku: str
    amount: Money


@dataclass(frozen=True)
class RecordedPayoutLine:
    order_id: str
    payee: str  # vendor id, or "platform" for the fee line
    amount: Money


@dataclass(frozen=True)
class RecordedLines:
    charges: list[RecordedCharge]
    refund_lines: list[RecordedRefundLine]
    payout_lines: list[RecordedPayoutLine]


def _read(exports_dir: Path, name: str) -> list[dict]:
    with (exports_dir / name).open(newline="") as f:
        return list(csv.DictReader(f))


def load_recorded_lines(exports_dir: Path = EXPORTS_DIR) -> RecordedLines:
    charges = [
        RecordedCharge(
            order_id=r["order_id"],
            charged_at=r["charged_at"],
            status=r["status"],
            amount=Money.from_cents(int(r["charged_cents"])),
        )
        for r in _read(exports_dir, "charges.csv")
    ]
    refund_lines = [
        RecordedRefundLine(
            order_id=r["order_id"],
            sku=r["sku"],
            amount=Money.from_cents(int(r["amount_cents"])),
        )
        for r in _read(exports_dir, "refund_lines.csv")
    ]
    payout_lines = [
        RecordedPayoutLine(
            order_id=r["order_id"],
            payee=r["payee"],
            amount=Money.from_cents(int(r["amount_cents"])),
        )
        for r in _read(exports_dir, "payout_lines.csv")
    ]
    return RecordedLines(charges=charges, refund_lines=refund_lines, payout_lines=payout_lines)


def months_in_range(from_month: str, to_month: str) -> list[str]:
    """Inclusive list of YYYY-MM months from ``from_month`` to ``to_month``."""
    fy, fm = int(from_month[:4]), int(from_month[5:7])
    ty, tm = int(to_month[:4]), int(to_month[5:7])
    if (fy, fm) > (ty, tm):
        raise ValueError(f"empty month range: {from_month}..{to_month}")
    months = []
    y, m = fy, fm
    while (y, m) <= (ty, tm):
        months.append(f"{y:04d}-{m:02d}")
        m += 1
        if m == 13:
            y, m = y + 1, 1
    return months

