import hashlib
import hmac
import json
from pathlib import Path

from services.notifications import build_events, load_subscriptions, write_outbox
from services.recorded import load_recorded_lines, months_in_range

EXPORTS_DIR = Path(__file__).resolve().parent.parent / "exports"

ORDER_EVENT_TYPES = {"order.fulfilled", "order.cancelled"}


def _sha256(path: Path) -> str:
    return hashlib.sha256(path.read_bytes()).hexdigest()


def _read_lines(path: Path) -> list[dict]:
    text = path.read_text()
    if not text:
        return []
    return [json.loads(line) for line in text.splitlines()]


def test_signatures_verify_with_subscriber_secret(tmp_path):
    write_outbox("2026-04", "2026-06", tmp_path)
    subs = {s.id: s for s in load_subscriptions()}

    checked = 0
    for sub_id, sub in subs.items():
        for obj in _read_lines(tmp_path / f"{sub_id}.jsonl"):
            expected = hmac.new(
                sub.secret.encode("utf-8"),
                json.dumps(obj["payload"], sort_keys=True, separators=(",", ":")).encode("utf-8"),
                hashlib.sha256,
            ).hexdigest()
            assert obj["signature"] == expected
            checked += 1
    assert checked > 0


def test_filtering_matches_each_subscribers_event_list(tmp_path):
    write_outbox("2026-04", "2026-06", tmp_path)
    for sub in load_subscriptions():
        events = {obj["event"] for obj in _read_lines(tmp_path / f"{sub.id}.jsonl")}
        assert events <= set(sub.events)


def test_ops_pager_only_gets_order_cancelled(tmp_path):
    write_outbox("2026-04", "2026-06", tmp_path)
    events = [obj["event"] for obj in _read_lines(tmp_path / "ops-pager.jsonl")]
    assert events
    assert set(events) == {"order.cancelled"}


def test_event_counts_tie_to_recorded_lines():
    events = build_events("2026-04", "2026-06")
    recorded = load_recorded_lines()
    valid_months = set(months_in_range("2026-04", "2026-06"))
    in_range_order_ids = {c.order_id for c in recorded.charges if c.month in valid_months}

    order_events = [e for e in events if e.event in ORDER_EVENT_TYPES]
    assert len(order_events) == len(in_range_order_ids)

    expected_refunds = [r for r in recorded.refund_lines if r.order_id in in_range_order_ids]
    refund_events = [e for e in events if e.event == "refund.recorded"]
    assert len(refund_events) == len(expected_refunds)

    expected_payouts = [p for p in recorded.payout_lines if p.order_id in in_range_order_ids]
    payout_events = [e for e in events if e.event == "payout.recorded"]
    assert len(payout_events) == len(expected_payouts)


def test_amounts_match_recorded_lines():
    events = build_events("2026-04", "2026-06")
    recorded = load_recorded_lines()
    charge_by_order = {c.order_id: c for c in recorded.charges}

    order_events = [e for e in events if e.event in ORDER_EVENT_TYPES]
    in_range_order_ids = {e.payload["order_id"] for e in order_events}

    # Spot-check: every order event's charged_cents equals its recorded charge.
    for e in order_events:
        charge = charge_by_order[e.payload["order_id"]]
        assert e.payload["charged_cents"] == charge.amount.to_cents()
        assert e.payload["charged_at"] == charge.charged_at

    # Aggregate: total charged across order events equals recorded total for
    # those same orders.
    assert sum(e.payload["charged_cents"] for e in order_events) == sum(
        charge_by_order[oid].amount.to_cents() for oid in in_range_order_ids
    )

    refund_events = [e for e in events if e.event == "refund.recorded"]
    expected_refund_total = sum(
        r.amount.to_cents() for r in recorded.refund_lines if r.order_id in in_range_order_ids
    )
    assert sum(e.payload["amount_cents"] for e in refund_events) == expected_refund_total

    payout_events = [e for e in events if e.event == "payout.recorded"]
    expected_payout_total = sum(
        p.amount.to_cents() for p in recorded.payout_lines if p.order_id in in_range_order_ids
    )
    assert sum(e.payload["amount_cents"] for e in payout_events) == expected_payout_total


def test_ordering_is_sorted_by_spec():
    events = build_events("2026-04", "2026-06")

    def sort_key(e):
        if e.event == "payout.recorded":
            tiebreak = e.payload["payee"]
        elif e.event == "refund.recorded":
            tiebreak = e.payload["sku"]
        else:
            tiebreak = ""
        return (e.payload["charged_at"], e.payload["order_id"], e.event, tiebreak)

    keys = [sort_key(e) for e in events]
    assert keys == sorted(keys)


def test_writing_twice_is_byte_identical(tmp_path):
    dir_a = tmp_path / "a"
