def test_per_fulfilled_order_vendor_fees_sum_to_platform_line():
    recorded = load_recorded_lines()
    orders_by_id = {o.id: o for o in load_orders()}
    from libs.money import Money

    for charge in recorded.charges:
        if charge.status != "fulfilled":
            continue
        order = orders_by_id[charge.order_id]
        vendor_weights: dict[str, int] = {}
        for item in order.items:
            vendor_weights[item.vendor] = vendor_weights.get(item.vendor, 0) + (
                item.price * item.qty
            ).to_cents()
        vendors = sorted(vendor_weights)
        weights = [vendor_weights[v] for v in vendors]
        shares = charge.amount.allocate(weights)
        payout_lines = {
            (l.order_id, l.payee): l.amount
            for l in recorded.payout_lines
            if l.order_id == charge.order_id
        }
        fee_sum = Money(0)
        for vendor, share in zip(vendors, shares):
            payout = payout_lines.get((charge.order_id, vendor), Money(0))
            fee_sum = fee_sum + (share - payout)
        platform_line = payout_lines.get((charge.order_id, "platform"), Money(0))
        assert fee_sum.to_cents() == platform_line.to_cents(), charge.order_id


